INSERT INTO standard_requirements (clause_id, code, text, obligation, evidence_types, measurable_criteria, risk_if_missing, order_index) VALUES
    ('51020004-0000-0000-0000-000000000002', '7.1.5.2.1', 'L''organisme doit conserver des registres d''étalonnage/vérification de tous les équipements de mesure, y compris logiciels et étalons.', 'MUST', 'Registres d''étalonnage, certificats, plan métrologie', 'Étalonnages à jour, traçabilité métrologique assurée', 'HIGH', 1),
    ('51020004-0000-0000-0000-000000000003', '7.2.1', 'L''organisme doit établir un processus pour identifier les besoins en formation et atteindre la compétence du personnel affecté aux activités impactant la qualité produit.', 'MUST', 'Plan de formation, matrice de polyvalence', 'Compétences évaluées et écarts comblés', 'HIGH', 2),
    ('51020005-0000-0000-0000-000000000003', '8.3.5.2', 'L''organisme doit identifier les caractéristiques spéciales et les documenter dans les plans de surveillance et la documentation de conception.', 'MUST', 'Plans de surveillance, AMDEC, marquage CS', 'Caractéristiques spéciales tracées de bout en bout', 'CRITICAL', 1),
    ('51020005-0000-0000-0000-000000000004', '8.4.2.3.1', 'L''organisme doit exiger de ses fournisseurs un système de management de la qualité du logiciel embarqué (ex. évaluation Automotive SPICE).', 'MUST', 'Évaluation A-SPICE fournisseurs, audits logiciel', 'Fournisseurs logiciel évalués', 'HIGH', 2),
    ('51020005-0000-0000-0000-000000000006', '8.5.6.1.1', 'L''organisme doit maîtriser et documenter les changements temporaires de processus de production et conserver l''autorisation préalable.', 'MUST', 'Registre des changements temporaires, autorisations', 'Changements temporaires tracés et autorisés', 'HIGH', 3),
    ('51020006-0000-0000-0000-000000000002', '9.2.2.4', 'L''organisme doit réaliser des audits produit aux étapes appropriées de production et de livraison selon un programme.', 'MUST', 'Programme et rapports d''audit produit', 'Audits produit planifiés et réalisés', 'MEDIUM', 1),
    ('51020007-0000-0000-0000-000000000002', '10.2.4', 'L''organisme doit utiliser des méthodes de détrompage (Poka-Yoke) pour prévenir l''occurrence de non-conformités, proportionnées au risque.', 'MUST', 'Catalogue de dispositifs Poka-Yoke, AMDEC', 'Dispositifs anti-erreur déployés sur risques élevés', 'HIGH', 1);
INSERT INTO standard_requirements (clause_id, code, text, obligation, evidence_types, measurable_criteria, risk_if_missing, order_index) VALUES
    ('52020004-0000-0000-0000-000000000001', '4.1.1', 'L''organisme doit tenir compte des exigences sectorielles aérospatiales, de défense et spatiales pertinentes dans la détermination de son contexte.', 'MUST', 'Analyse de contexte aéro, exigences clients/réglementaires', 'Exigences sectorielles identifiées', 'HIGH', 1),
    ('52020005-0000-0000-0000-000000000001', '5.1.1', 'La direction doit promouvoir la conscience de la sécurité produit et du comportement éthique à tous les niveaux.', 'MUST', 'Programme de sensibilisation sécurité produit', 'Sensibilisation déployée et tracée', 'HIGH', 1),
    ('52020006-0000-0000-0000-000000000002', '6.1.2', 'L''organisme doit planifier et mettre en œuvre un processus de gestion du risque opérationnel adapté à ses produits et services.', 'MUST', 'Processus de gestion des risques, registre', 'Risques opérationnels évalués et traités', 'HIGH', 1),
    ('52020007-0000-0000-0000-000000000001', '7.2', 'L''organisme doit assurer la compétence du personnel via une formation aéronautique spécifique aux processus et exigences applicables.', 'MUST', 'Matrice de compétences, habilitations aéro', 'Compétences spécifiques à jour', 'HIGH', 1),
    ('52020007-0000-0000-0000-000000000002', '7.3', 'L''organisme doit sensibiliser le personnel à la prévention des pièces contrefaites et des corps étrangers (FOD).', 'MUST', 'Programme FOD, procédure pièces contrefaites', 'Sensibilisation FOD/contrefaçon réalisée', 'CRITICAL', 2),
    ('52020008-0000-0000-0000-000000000002', '8.1.3', 'L''organisme doit planifier et mettre en œuvre les processus nécessaires pour gérer la sécurité produit tout au long du cycle de vie.', 'MUST', 'Analyse de sécurité produit, plans associés', 'Sécurité produit analysée et maîtrisée', 'CRITICAL', 1),
    ('52020008-0000-0000-0000-000000000004', '8.3.4', 'L''organisme doit réaliser les activités de vérification et de validation de la conception, y compris les essais et la First Article Inspection (FAI).', 'MUST', 'Rapports V&V, FAI (AS9102)', 'V&V et FAI documentées', 'CRITICAL', 2),
    ('52020008-0000-0000-0000-000000000005', '8.4.3', 'L''organisme doit communiquer aux prestataires externes les exigences applicables et maîtriser leurs livrables.', 'MUST', 'Cahier des charges fournisseurs, surveillance', 'Exigences transmises et maîtrise exercée', 'HIGH', 3),
    ('52020008-0000-0000-0000-000000000006', '8.5.1.1', 'L''organisme doit maîtriser les équipements de production, outillages et logiciels utilisés pour la réalisation et la surveillance.', 'MUST', 'Registre équipements, plans de maintenance', 'Équipements maîtrisés et maintenus', 'HIGH', 4),
    ('52020008-0000-0000-0000-000000000010', '8.5.4', 'L''organisme doit préserver les éléments de sortie pendant la production et la livraison pour maintenir la conformité (manutention, conditionnement, FOD).', 'MUST', 'Procédures de préservation et conditionnement', 'Préservation assurée, zéro FOD', 'HIGH', 5),
    ('52020009-0000-0000-0000-000000000001', '9.1.1', 'L''organisme doit surveiller et mesurer la performance des prestataires externes (qualité, délais) selon des critères définis.', 'MUST', 'Scorecards fournisseurs, OTD/qualité', 'Performance fournisseurs suivie', 'MEDIUM', 1);
INSERT INTO standard_requirements (clause_id, code, text, obligation, evidence_types, measurable_criteria, risk_if_missing, order_index) VALUES
    ('53020004-0000-0000-0000-000000000001', '4.1.1', 'L''organisme doit documenter un SMQ et tenir à jour son efficacité conformément aux exigences réglementaires applicables aux dispositifs médicaux.', 'MUST', 'Manuel qualité, procédures SMQ DM', 'SMQ documenté et conforme à la réglementation', 'CRITICAL', 1),
    ('53020005-0000-0000-0000-000000000001', '5.5.2', 'La direction doit nommer un représentant de la direction responsable du SMQ et de la sensibilisation aux exigences réglementaires.', 'MUST', 'Lettre de nomination, fiche de fonction', 'Représentant nommé et mandaté', 'HIGH', 1),
    ('53020006-0000-0000-0000-000000000001', '6.4.1', 'L''organisme doit documenter les exigences relatives à l''environnement de travail nécessaires à la conformité du produit.', 'MUST', 'Procédures environnement de travail, contrôles', 'Conditions d''environnement maîtrisées', 'HIGH', 1),
    ('53020007-0000-0000-0000-000000000001', '7.1', 'L''organisme doit planifier la réalisation du produit, y compris la gestion des risques tout au long de la réalisation.', 'MUST', 'Plans de réalisation, dossier de gestion des risques (ISO 14971)', 'Planification et gestion des risques documentées', 'CRITICAL', 1),
    ('53020007-0000-0000-0000-000000000002', '7.2.1', 'L''organisme doit déterminer les exigences spécifiées par le client et les exigences réglementaires relatives au dispositif.', 'MUST', 'Revue des exigences, cahier des charges', 'Exigences déterminées et revues', 'HIGH', 2),
    ('53020007-0000-0000-0000-000000000003', '7.3.2', 'L''organisme doit planifier et maîtriser la conception et le développement, en définissant étapes, revues, vérifications et validations.', 'MUST', 'Plan de conception, jalons, revues', 'Conception maîtrisée et tracée', 'CRITICAL', 3),
    ('53020007-0000-0000-0000-000000000005', '7.3.9', 'L''organisme doit maîtriser les modifications de conception et de développement (identification, revue, vérification, validation, approbation).', 'MUST', 'Registre des modifications de conception', 'Modifications tracées et approuvées', 'CRITICAL', 4),
    ('53020007-0000-0000-0000-000000000006', '7.4.1', 'L''organisme doit établir des critères de sélection, d''évaluation et de réévaluation des fournisseurs en fonction du risque du dispositif.', 'MUST', 'Procédure achats, évaluations fournisseurs', 'Fournisseurs sélectionnés selon le risque', 'HIGH', 5),
    ('53020007-0000-0000-0000-000000000007', '7.5.2', 'L''organisme doit documenter les exigences de propreté du produit ou de maîtrise de la contamination.', 'MUST', 'Procédures de propreté/contamination', 'Exigences de propreté définies', 'HIGH', 6),
    ('53020007-0000-0000-0000-000000000009', '7.5.6', 'L''organisme doit valider les processus de production et de prestation de service dont le résultat ne peut être vérifié a posteriori.', 'MUST', 'Protocoles de validation (IQ/OQ/PQ)', 'Processus spéciaux validés', 'CRITICAL', 7),
    ('53020007-0000-0000-0000-000000000011', '7.5.9', 'L''organisme doit établir la traçabilité des dispositifs et conserver les enregistrements conformément aux exigences réglementaires.', 'MUST', 'Système de traçabilité, UDI, enregistrements', 'Traçabilité assurée et conservée', 'CRITICAL', 8),
    ('53020008-0000-0000-0000-000000000003', '8.3.4', 'L''organisme doit entreprendre des actions correctives pour éliminer les causes des non-conformités et prévenir leur réapparition, sans délai indu.', 'MUST', 'Registre CAPA, preuves d''efficacité', 'CAPA traitées et efficacité vérifiée', 'CRITICAL', 1);
INSERT INTO standard_requirements (clause_id, code, text, obligation, evidence_types, measurable_criteria, risk_if_missing, order_index) VALUES
    ('54020001-0000-0000-0000-000000000001', '11.1', 'L''organisme doit déterminer le périmètre des enregistrements et signatures électroniques soumis à la Part 11.', 'MUST', 'Inventaire des systèmes GxP, analyse d''applicabilité', 'Périmètre Part 11 défini', 'HIGH', 1),
    ('54020001-0000-0000-0000-000000000002', '11.2', 'L''organisme doit s''assurer que les enregistrements électroniques satisfont aux exigences applicables et sont équivalents aux enregistrements papier.', 'MUST', 'Procédures d''équivalence, SOP', 'Équivalence documentée', 'MEDIUM', 2),
    ('54020001-0000-0000-0000-000000000003', '11.3', 'L''organisme doit définir et appliquer les définitions de la Part 11 dans ses procédures (système fermé/ouvert, signature, etc.).', 'SHOULD', 'Glossaire, SOP', 'Définitions appliquées', 'LOW', 3),
    ('54020002-0000-0000-0000-000000000002', '11.10(b)', 'Le système doit permettre de générer des copies exactes et complètes des enregistrements sous forme lisible et électronique pour inspection.', 'MUST', 'Tests de génération de copies, export', 'Copies exactes démontrées', 'HIGH', 1),
    ('54020002-0000-0000-0000-000000000003', '11.10(c)', 'Les enregistrements doivent être protégés pour permettre leur récupération exacte et fidèle pendant toute la période de conservation.', 'MUST', 'Politique de sauvegarde/archivage, tests de restauration', 'Récupération validée, rétention respectée', 'CRITICAL', 2),
    ('54020002-0000-0000-0000-000000000004', '11.10(d)', 'L''accès au système doit être limité aux individus autorisés.', 'MUST', 'Matrice des droits, revue des accès', 'Accès restreint et revu périodiquement', 'CRITICAL', 3),
    ('54020002-0000-0000-0000-000000000006', '11.10(f)', 'Le système doit comporter des contrôles opérationnels pour imposer le séquencement autorisé des étapes et événements.', 'MUST', 'Configuration workflow, tests OQ', 'Séquencement contrôlé', 'HIGH', 4),
    ('54020002-0000-0000-0000-000000000008', '11.10(h)', 'Le système doit comporter des contrôles de validité de la source des données (terminal/device).', 'SHOULD', 'Configuration, tests device checks', 'Contrôles device en place le cas échéant', 'MEDIUM', 5),
    ('54020002-0000-0000-0000-000000000009', '11.10(i)', 'Les personnes utilisant le système doivent posséder l''éducation, la formation et l''expérience requises.', 'MUST', 'Dossiers de formation, qualifications', 'Formation tracée pour tous les utilisateurs', 'HIGH', 6),
    ('54020002-0000-0000-0000-000000000010', '11.10(k)', 'L''organisme doit maîtriser la documentation des systèmes (distribution, accès, contrôle des révisions et de l''historique des changements).', 'MUST', 'Gestion documentaire validée, change control', 'Documentation maîtrisée et tracée', 'HIGH', 7),
    ('54020002-0000-0000-0000-000000000011', '11.30', 'Pour les systèmes ouverts, l''organisme doit mettre en œuvre des mesures supplémentaires (chiffrement, signatures numériques) pour garantir authenticité, intégrité et confidentialité.', 'MUST', 'Architecture sécurité, chiffrement', 'Mesures systèmes ouverts en place', 'CRITICAL', 8),
    ('54020002-0000-0000-0000-000000000012', '11.50', 'Les enregistrements signés doivent afficher le nom du signataire, la date/heure et la signification de la signature.', 'MUST', 'Configuration des manifestations de signature', 'Manifestations de signature complètes', 'HIGH', 9);
INSERT INTO standard_requirements (clause_id, code, text, obligation, evidence_types, measurable_criteria, risk_if_missing, order_index) VALUES
    ('55020004-0000-0000-0000-000000000001', '4.1', 'L''organisme doit déterminer les enjeux externes et internes pertinents pour le SMSDA et sa capacité à fournir des produits et services sûrs.', 'MUST', 'Analyse de contexte filière alimentaire', 'Enjeux documentés', 'HIGH', 1),
    ('55020004-0000-0000-0000-000000000002', '4.2', 'L''organisme doit déterminer les parties intéressées pertinentes pour le SMSDA (consommateurs, autorités sanitaires, clients).', 'MUST', 'Registre des parties intéressées', 'Exigences recensées', 'HIGH', 2),
    ('55020005-0000-0000-0000-000000000001', '5.2', 'La direction doit établir une politique de sécurité des denrées alimentaires adaptée et engageante.', 'MUST', 'Politique sécurité des aliments signée', 'Politique datée, signée, diffusée', 'CRITICAL', 1),
    ('55020006-0000-0000-0000-000000000001', '6.2', 'L''organisme doit établir des objectifs de sécurité des aliments mesurables et planifier les actions pour les atteindre.', 'MUST', 'Objectifs SMSDA, plan d''actions', 'Objectifs mesurables et suivis', 'HIGH', 1),
    ('55020007-0000-0000-0000-000000000001', '7.1.6', 'L''organisme doit maîtriser les processus, produits et services fournis en externe (prestataires, sous-traitants) ayant un impact sur la sécurité des aliments.', 'MUST', 'Évaluation fournisseurs, cahiers des charges', 'Prestataires évalués et maîtrisés', 'CRITICAL', 1),
    ('55020007-0000-0000-0000-000000000002', '7.2', 'L''organisme doit s''assurer de la compétence de l''équipe sécurité des aliments (HACCP) et du personnel impactant la sécurité.', 'MUST', 'Matrice de compétences, formations HACCP', 'Équipe HACCP compétente et formée', 'HIGH', 2),
    ('55020008-0000-0000-0000-000000000003', '8.4.1', 'L''organisme doit établir des procédures de préparation et de réponse aux situations d''urgence pouvant impacter la sécurité des aliments.', 'MUST', 'Plans d''urgence, procédure de rappel/retrait', 'Procédures testées, exercices de rappel', 'CRITICAL', 1),
    ('55020008-0000-0000-0000-000000000004', '8.5.1', 'L''organisme doit réaliser les étapes préliminaires à l''analyse des dangers (caractéristiques produits, usage prévu, diagrammes de flux).', 'MUST', 'Diagrammes de flux validés, fiches produits', 'Étapes préliminaires documentées et vérifiées', 'CRITICAL', 2),
    ('55020008-0000-0000-0000-000000000008', '8.8', 'L''organisme doit vérifier que les PRP et le plan de maîtrise des dangers (HACCP) sont mis en œuvre et efficaces.', 'MUST', 'Plan de vérification, résultats', 'Vérifications planifiées et réalisées', 'CRITICAL', 3),
    ('55020008-0000-0000-0000-000000000009', '8.9.1', 'L''organisme doit maîtriser les produits non conformes et les corrections/actions correctives associées (y compris retrait/rappel).', 'MUST', 'Procédure NC produits, registre rappels', 'NC produits maîtrisées', 'CRITICAL', 4),
    ('55020009-0000-0000-0000-000000000001', '9.2', 'L''organisme doit réaliser des audits internes du SMSDA à intervalles planifiés.', 'MUST', 'Programme et rapports d''audit interne', 'Audit interne ≥ 1/an', 'HIGH', 1),
    ('55020009-0000-0000-0000-000000000002', '9.3', 'La direction doit procéder à la revue du SMSDA à intervalles planifiés.', 'MUST', 'PV de revue de direction', 'Revue ≥ 1/an avec décisions', 'CRITICAL', 2),
    ('55020010-0000-0000-0000-000000000001', '10.2', 'L''organisme doit réagir aux non-conformités et entreprendre les actions correctives appropriées pour en éliminer les causes.', 'MUST', 'Registre CAPA, preuves d''efficacité', 'NC traitées et efficacité vérifiée', 'CRITICAL', 1);
INSERT INTO standard_requirements (clause_id, code, text, obligation, evidence_types, measurable_criteria, risk_if_missing, order_index) VALUES
    ('56020002-0000-0000-0000-000000000003', 'Art. 7', 'L''entité financière doit utiliser et maintenir des systèmes, protocoles et outils TIC fiables, résilients et technologiquement à jour.', 'MUST', 'Cartographie SI, inventaire des actifs TIC', 'Systèmes TIC maintenus et résilients', 'HIGH', 1),
    ('56020002-0000-0000-0000-000000000005', 'Art. 9', 'L''entité doit mettre en œuvre des politiques et mesures de protection et de prévention des risques liés aux TIC.', 'MUST', 'Politiques de sécurité, mesures techniques/organisationnelles', 'Mesures de protection déployées', 'CRITICAL', 2),
    ('56020002-0000-0000-0000-000000000006', 'Art. 10', 'L''entité doit disposer de mécanismes de détection rapide des activités anormales et des cybermenaces.', 'MUST', 'SIEM, supervision, seuils d''alerte', 'Détection en place et testée', 'CRITICAL', 3),
    ('56020002-0000-0000-0000-000000000007', 'Art. 11', 'L''entité doit mettre en place une politique de continuité des activités TIC et des plans de réponse et de reprise.', 'MUST', 'PCA TIC, plans de reprise (DRP), RTO/RPO', 'Plans testés ≥ 1/an', 'CRITICAL', 4),
    ('56020002-0000-0000-0000-000000000008', 'Art. 12', 'L''entité doit tirer des enseignements des incidents TIC et faire évoluer ses capacités (analyse post-incident).', 'MUST', 'Revues post-incident, plans d''amélioration', 'Retours d''expérience formalisés', 'MEDIUM', 5),
    ('56020003-0000-0000-0000-000000000002', 'Art. 18', 'L''entité doit classifier les incidents liés aux TIC selon des critères de matérialité définis par le règlement.', 'MUST', 'Procédure de classification des incidents', 'Incidents classifiés selon les critères DORA', 'HIGH', 1),
    ('56020004-0000-0000-0000-000000000002', 'Art. 25', 'L''entité doit réaliser un programme de tests de résilience opérationnelle numérique, incluant des tests annuels appropriés.', 'MUST', 'Programme de tests, rapports', 'Tests réalisés ≥ 1/an', 'HIGH', 1),
    ('56020005-0000-0000-0000-000000000001', 'Art. 28', 'L''entité doit gérer le risque lié aux prestataires tiers de services TIC dans le cadre de son dispositif de gestion des risques.', 'MUST', 'Politique tiers TIC, registre d''information', 'Risques tiers TIC gérés et tracés', 'CRITICAL', 1),
    ('56020005-0000-0000-0000-000000000002', 'Art. 29', 'L''entité doit évaluer le risque de concentration TIC avant de conclure un accord avec un prestataire tiers.', 'MUST', 'Analyse de concentration, due diligence', 'Concentration évaluée avant contractualisation', 'HIGH', 2),
    ('56020005-0000-0000-0000-000000000004', 'Art. 31', 'L''entité doit identifier les prestataires tiers de services TIC critiques et appliquer les exigences renforcées associées.', 'MUST', 'Registre des prestataires critiques, clauses contractuelles', 'Prestataires critiques identifiés', 'HIGH', 3);
